<span class="line"><span style="color:#CBA6F7;">    async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> show_tool_result</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> result</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">ToolResult</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#9399B2;">()</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">;</span></span>
